type Customer = { yearsWithMHPCO: number };

export const quote = (_customer: Customer, items: Item[]): number => {
  if (items.length === 0) return PROCESSING_FEE;
  const item = items[0];
  if (item.type === "sword") {
    return 100 + 10 + PROCESSING_FEE;
  }
  return PROCESSING_FEE;
};

export const claim = (..._args: unknown[]): unknown => {
  return undefined;
};

