const PROCESSING_FEE = 5;

const BASE_PRICE_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
};

type Item = { type: string };
type Customer = { yearsWithMHPCO: number };

const priceForItem = (item: Item): number => {
  const basePrice = BASE_PRICE_BY_ITEM_TYPE[item.type] ?? 0;
  const firstInsuranceSurcharge = basePrice * 0.1;
  return basePrice + firstInsuranceSurcharge;
};

export const quote = (_customer: Customer, items: Item[]): number => {
  const itemsTotal = items.reduce((sum, item) => sum + priceForItem(item), 0);
  return itemsTotal + PROCESSING_FEE;
};

export const claim = (..._args: unknown[]): unknown => {
  return undefined;
};

