const PROCESSING_FEE = 5;
const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
const COMPONENT_BASE_PRICE = 25;
const COMPONENT_BLOCK_SIZE = 3;
const COMPONENT_BLOCK_PRICE = 60;

const BASE_PRICE_BY_ITEM_TYPE: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const COMPONENT_TYPES = new Set(["rune", "moonstone"]);

type Item = { type: string };
type Customer = { yearsWithMHPCO: number };

const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const basePriceFor = (item: Item): number =>
  BASE_PRICE_BY_ITEM_TYPE[item.type] ?? 0;

const priceForItem = (item: Item): number => {
  const basePrice = basePriceFor(item);
  return basePrice + basePrice * FIRST_INSURANCE_SURCHARGE_RATE;
};

const componentsBasePrice = (items: Item[]): number => {
  const groups = new Map<string, number>();
  for (const item of items) {
    if (!isComponent(item)) continue;
    groups.set(item.type, (groups.get(item.type) ?? 0) + 1);
  }
  let total = 0;
  for (const count of groups.values()) {
    const blocks = Math.floor(count / COMPONENT_BLOCK_SIZE);
    const remainder = count % COMPONENT_BLOCK_SIZE;
    total += blocks * COMPONENT_BLOCK_PRICE + remainder * COMPONENT_BASE_PRICE;
  }
  return total;
};

export const quote = (_customer: Customer, items: Item[]): number => {
  const mainItemsTotal = items
    .filter((i) => !isComponent(i))
    .reduce((sum, item) => sum + priceForItem(item), 0);
  const componentsBase = componentsBasePrice(items);
  const componentsTotal =
    componentsBase + componentsBase * FIRST_INSURANCE_SURCHARGE_RATE;
  return Math.ceil(mainItemsTotal + componentsTotal + PROCESSING_FEE);
};

export const claim = (..._args: unknown[]): unknown => {
  return undefined;
};

