import { describe, it, expect } from "vitest";
import { quote, claim } from "./claim-office.js";

describe("MHPCO Claim Office", () => {
  // Quote — empty and single items
  it("empty item list yields premium of 5 G (processing fee only)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [])).toBe(5);
  });
  it("a single sword yields premium of 115 G (100 base + 10 first + 5 fee)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "sword", material: "steel", enchantment: 1, cursed: false }])).toBe(115);
  });
  it("a single amulet yields premium of 71 G (60 base + 6 first + 5 fee)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "amulet", material: "silver", enchantment: 1, cursed: false }])).toBe(71);
  });
  it("a single staff yields premium of 93 G (80 base + 8 first + 5 fee)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "staff", material: "oak", enchantment: 1, cursed: false }])).toBe(93);
  });
  it("a single potion yields premium of 49 G (40 base + 4 first + 5 fee)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "potion", material: "glass", enchantment: 1, cursed: false }])).toBe(49);
  });

  // Components
  it("a single rune (component) yields premium of 33 G (25 base + 2.5 first + 5 fee → rounded up)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }])).toBe(33);
  });
  it("2 runes yield premium of 60 G (50 base + 5 first + 5 fee)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }])).toBe(60);
  });
  it("3 runes (block) yield premium of 71 G (60 base + 6 first + 5 fee)", () => {
    expect(quote({ yearsWithMHPCO: 0 }, [{ type: "rune" }, { type: "rune" }, { type: "rune" }])).toBe(71);
  });
  it.todo("4 runes yield premium of 115 G (100 base + 10 first + 5 fee)");
  it.todo("3 runes + 3 moonstones (two blocks) yield premium of 137 G (120 base + 12 first + 5 fee)");
  it.todo("2 runes + 1 moonstone yields premium of 88 G (75 base + 7.5 first + 5 fee → rounded up)");

  // Premium modifiers (single item, newcomer)
  it.todo("cursed sword (newcomer, enchantment 3) yields premium of 165 G");
  it.todo("highly enchanted sword (enchantment 5, not cursed, newcomer) yields premium of 148 G (100 + 30 high + 10 first + 5 fee = 145; wait recompute)");
  it.todo("sword with enchantment 4 (newcomer, not cursed) yields premium of 115 G (no high-enchantment surcharge)");

  // Loyalty discount & follow-up contract
  it.todo("long-standing customer (2+ years) with a single sword yields premium of 95 G (100 + 10 first − 20 loyalty + 5 fee)");
  it.todo("second contract of a long-standing customer adds the 15% follow-up discount");

  // Multi-item policies and modifier scope
  it.todo("policy with cursed sword + plain amulet yields premium of 220 G (210 + 16 first + 5 fee ... per integration rules)");

  // Quote rounding
  it.todo("premium with fractional result is rounded up in MHPCO's favor");

  // Claim — basic
  it.todo("claim on a sword (steel, enchantment 3) with damage 500 G pays 400 G and remainingCap 1600 G");
  it.todo("claim on a rune with damage 200 G pays 100 G (full minus 100 deductible)");

  // Claim — special clauses
  it.todo("dragon-material sword (enchantment 9) damage 1000 G pays 400 G (50% rule wins then deductible)");
  it.todo("dragon-material sword (enchantment 5) damage 800 G pays 700 G (full minus deductible)");
  it.todo("steel sword (enchantment 9) damage 1000 G pays 400 G (50% then deductible)");

  // Claim — multiple damages
  it.todo("claim with two damages (sword + amulet) applies deductible per damage entry");

  // Claim — cap and successive claims
  it.todo("successive claims exhaust the cap and reduce later payouts");

  // CLI / scenario integration
  it.todo("scenario with a quote step returns premium in results");
  it.todo("scenario with a quote followed by a claim returns premium then payout+remainingCap");
  it.todo("unknown item type in quote causes error (rejected)");
  it.todo("claim referencing item not in policy is rejected");
  it.todo("claim with negative damage amount is rejected");
});

