type Policy = { items: Item[] };
type Damage = { itemType: string; amount: number };
type Incident = { cause?: string; damages: Damage[] };
type ClaimResult = { payout: number; remainingCap: number };

const policyInsuranceSum = (policy: Policy): number =>
  sum(policy.items.map((item) => INSURANCE_VALUE_BY_ITEM_TYPE[item.type] ?? 0));

const policyCap = (policy: Policy): number =>
  policyInsuranceSum(policy) * CAP_MULTIPLIER;

const payoutForDamage = (damage: Damage): number =>
  Math.max(0, damage.amount - DEDUCTIBLE);

export const claim = (
  policy: Policy,
  incident: Incident,
  alreadyPaid: number = 0,
): ClaimResult => {
  const cap = policyCap(policy);
  const remainingBefore = cap - alreadyPaid;
  const desiredPayout = sum(incident.damages.map(payoutForDamage));
  const payout = Math.min(desiredPayout, remainingBefore);
  const remainingCap = remainingBefore - payout;
  return { payout: Math.floor(payout), remainingCap };
};

