    expect(first).toEqual({ payout: 1400, remainingCap: 600 });
    const incident2 = { cause: "fire", damages: [{ itemType: "sword", amount: 1500 }] };
    const second = claim(policy, incident2, 1400);
    expect(second).toEqual({ payout: 600, remainingCap: 0 });
  });

